import{_ as e,o as l,c as i,ai as o}from"./chunks/framework.ampVZV4B.js";const _=JSON.parse('{"title":"04 API 入门：用 Python 写一个最小调用脚本","description":"","frontmatter":{},"headers":[],"relativePath":"ai/stage-1-llm/04-api-python-minimal.md","filePath":"ai/stage-1-llm/04-api-python-minimal.md"}'),t={name:"ai/stage-1-llm/04-api-python-minimal.md"};function n(r,a,d,c,h,s){return l(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="_04-api-入门-用-python-写一个最小调用脚本" tabindex="-1">04 API 入门：用 Python 写一个最小调用脚本 <a class="header-anchor" href="#_04-api-入门-用-python-写一个最小调用脚本" aria-label="Permalink to “04 API 入门：用 Python 写一个最小调用脚本”">​</a></h1><blockquote><p>目标：把“会聊天”升级成“会写脚本调用”，为后面 Agent/工具链打基础。</p></blockquote><h2 id="_1-你要实现的最小功能" tabindex="-1">1）你要实现的最小功能 <a class="header-anchor" href="#_1-你要实现的最小功能" aria-label="Permalink to “1）你要实现的最小功能”">​</a></h2><ul><li>输入：一段文本（命令行/文件）</li><li>输出：模型生成的 Markdown（保存到 <code>outputs/</code>）</li></ul><h2 id="_2-推荐项目结构-最小" tabindex="-1">2）推荐项目结构（最小） <a class="header-anchor" href="#_2-推荐项目结构-最小" aria-label="Permalink to “2）推荐项目结构（最小）”">​</a></h2><ul><li><code>main.py</code></li><li><code>inputs/</code></li><li><code>outputs/</code></li></ul><h2 id="_3-依赖与运行-建议用-uv" tabindex="-1">3）依赖与运行（建议用 uv） <a class="header-anchor" href="#_3-依赖与运行-建议用-uv" aria-label="Permalink to “3）依赖与运行（建议用 uv）”">​</a></h2><ul><li>用 <code>uv add ...</code> 安装你需要的 SDK（按你选择的平台来）</li><li>用 <code>uv run main.py</code> 运行</li></ul><blockquote><p>这一篇不强绑定某一家模型 SDK，你按你实际选择的平台 Quickstart 抄一版即可。</p></blockquote><h2 id="_4-关键点-写脚本时别踩坑" tabindex="-1">4）关键点（写脚本时别踩坑） <a class="header-anchor" href="#_4-关键点-写脚本时别踩坑" aria-label="Permalink to “4）关键点（写脚本时别踩坑）”">​</a></h2><ul><li>把 Key 放环境变量，不要硬编码</li><li>控制输出格式：让模型只输出 Markdown</li><li>做好失败重试/超时（后面再补也行，但要有意识）</li></ul><h2 id="_5-今日练习-30-60-分钟" tabindex="-1">5）今日练习（30～60 分钟） <a class="header-anchor" href="#_5-今日练习-30-60-分钟" aria-label="Permalink to “5）今日练习（30～60 分钟）”">​</a></h2><ul><li>让脚本支持两种输入： <ul><li>直接从命令行传入文本</li><li>从 <code>inputs/xx.md</code> 读取</li></ul></li><li>输出固定写到 <code>outputs/summary.md</code></li></ul>',13)])])}const p=e(t,[["render",n]]);export{_ as __pageData,p as default};
